import time
import math
import random

def solve(cities):
    t0 = time.time()
    n = len(cities)
    budget = 0.04 * n

    if n == 1:
        return [0]
    if n == 2:
        return [0, 1]
    if n == 3:
        return [0, 1, 2]

    xs = [c[0] for c in cities]
    ys = [c[1] for c in cities]

    def dist(i, j):
        dx = xs[i] - xs[j]
        dy = ys[i] - ys[j]
        return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    # Precompute distance matrix for small n
    if n <= 400:
        D = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(i+1, n):
                d = int(math.sqrt((xs[i]-xs[j])**2 + (ys[i]-ys[j])**2) + 0.5)
                D[i][j] = d
                D[j][i] = d
        def dist(i, j):
            return D[i][j]

    # Build candidate list
    k = min(15, n - 1)
    candidates = []
    for i in range(n):
        row = [(D[i][j], j) for j in range(n) if j != i]
        row.sort()
        candidates.append([j for _, j in row[:k]])

    def tour_length(tour):
        total = 0
        for i in range(n):
            total += dist(tour[i], tour[(i+1) % n])
        return total

    def nn_tour(start):
        visited = [False] * n
        tour = [start]
        visited[start] = True
        for _ in range(n - 1):
            cur = tour[-1]
            best_d = 10**18
            best_j = -1
            for j in candidates[cur]:
                if not visited[j]:
                    d = dist(cur, j)
                    if d < best_d:
                        best_d = d
                        best_j = j
            if best_j == -1:
                for j in range(n):
                    if not visited[j]:
                        d = dist(cur, j)
