import time
import math
import random

def solve(cities):
    t0 = time.time()
    n = len(cities)
    budget = 0.04 * n

    xs = [c[0] for c in cities]
    ys = [c[1] for c in cities]

    def dist(i, j):
        dx = xs[i] - xs[j]
        dy = ys[i] - ys[j]
        return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    # Precompute distance matrix for small n
    if n <= 600:
        D = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(i+1, n):
                d = dist(i, j)
                D[i][j] = d
                D[j][i] = d
        def d(i, j): return D[i][j]
    else:
        def d(i, j): return dist(i, j)

    K = min(15, n-1)
    neighbors = []
    for i in range(n):
        row = sorted(range(n), key=lambda j: D[i][j] if j != i else 10**9)
        neighbors.append(row[:K])

    def tour_length(tour):
        s = 0
        for i in range(n):
            s += D[tour[i]][tour[(i+1)%n]]
        return s

    def nearest_neighbor(start):
        visited = [False]*n
        tour = [start]
        visited[start] = True
        cur = start
        for _ in range(n-1):
            best_d = 10**9
            best_j = -1
            for nb in neighbors[cur]:
                if not visited[nb]:
                    dd = D[cur][nb]
                    if dd < best_d:
                        best_d = dd
                        best_j = nb
                        break
            if best_j == -1:
                for j in range(n):
                    if not visited[j]:
                        dd = D[cur][j]
                        if dd < best_d:
                            best_d = dd
                            best_j = j
            tour.append(best_j)
            visited[best_j] = True
            cur = best_j
        return tour

    def two_opt(tour, time_limit):
        pos = [0]*n
        for i, c in enumerate(tour):
            pos[c] = i
        dont_look = [False]*n
        improved = True
        while improved:
            improved = False
            for idx in range(n):
                if time.time() - t0 >= time_limit:
                    return tour
                if dont_look[tour[idx]]:
                    continue
                i = idx
                ci = tour[i]
                i1 = (i+1)%n
                ci1 = tour[i1]
                d_ci_ci1 = D[ci][ci1]
                made = False
                for cj in neighbors[ci]:
                    if D[ci][cj] >= d_ci_ci1:
                        break
                    j = pos[cj]
                    j1 = (j+1)%n
                    cj1 = tour[j1]
                    if cj == ci1 or cj1 == ci:
                        continue
                    gain = d_ci_ci1 + D[cj][cj1] - D[ci][cj] - D[ci1][cj1]
                    if gain > 0:
                        # reverse segment between i1 and j
                        if i < j:
                            l, r = i1, j
                            tour[l:r+1] = tour[l:r+1][::-1]
                            for k in range(l, r+1):
                                pos[tour[k]] = k
                        else:
                            l, r = j1, i
                            tour[l:r+1] = tour[l:r+1][::-1]
                            for k in range(l, r+1):
                                pos[tour[k]] = k
                        dont_look[ci] = False
                        dont_look[ci1] = False
                        dont_look[cj] = False
                        dont_look[cj1] = False
                        improved = True
                        made = True
                        break
                if not made:
                    dont_look[ci] = True
        return tour

    def or_opt(tour, time_limit):
        pos = [0]*n
        for i, c in enumerate(tour):
            pos[c] = i
        improved = True
        while improved:
            improved = False
            if time.time() - t0 >= time_limit:
                return tour
            for seg_len in [1, 2, 3]:
                for idx in range(n):
                    if time.time() - t0 >= time_limit:
                        return tour
                    i = idx
                    prev_i = (i-1)%n
                    end_i = (i+seg_len-1)%n
                    next_end = (end_i+1)%n
                    c_prev = tour[prev_i]
                    c_start = tour[i]
                    c_end = tour[end_i]
                    c_next = tour[next_end]
                    if c_prev == c_next:
                        continue
                    remove_gain = D[c_prev][c_start] + D[c_end][c_next] - D[c_prev][c_next]
                    for nb in neighbors[c_start]:
                        nb_pos = pos[nb]
                        # check nb not in segment
                        in_seg = False
                        k = i
                        for _ in range(seg_len):
                            if tour[k] == nb:
                                in_seg = True
                                break
                            k = (k+1)%n
                        if in_seg or nb_pos == prev_i:
                            continue
                        nb1_pos = (nb_pos+1)%n
                        cnb1 = tour[nb1_pos]
                        # check cnb1 not in segment
                        in_seg2 = False
                        k = i
                        for _ in range(seg_len):
                            if tour[k] == cnb1:
                                in_seg2 = True
                                break
                            k = (k+1)%n
                        if in_seg2:
                            continue
                        insert_cost = D[nb][c_start] + D[c_end][cnb1] - D[nb][cnb1]
                        if remove_gain - insert_cost > 0:
                            # extract segment
                            seg = []
                            k = i
                            for _ in range(seg_len):
                                seg.append(tour[k])
                                k = (k+1)%n
                            # rebuild tour: go from next_end, skip segment indices
                            seg_set = set(id(x) for x in seg)
                            # use positions
                            seg_pos = set()
                            k = i
                            for _ in range(seg_len):
                                seg_pos.add(k)
                                k = (k+1)%n
                            new_tour = []
                            k = next_end
                            inserted = False
                            count = 0
                            while count < n - seg_len:
                                if time.time() - t0 >= time_limit:
                                    return tour
                                new_tour.append(tour[k])
                                if tour[k] == nb and not inserted:
                                    new_tour.extend(seg)
                                    inserted = True
                                k = (k+1)%n
                                while k in seg_pos and count < n:
                                    k = (k+1)%n
                                count += 1
                            if len(new_tour) == n:
                                tour[:] = new_tour
                                for ii, c in enumerate(tour):
                                    pos[c] = ii
                                improved = True
                                break
                    if improved:
                        break
                if improved:
                    break
        return tour

    def double_bridge(tour):
        if n < 8:
            return tour[:]
        positions = sorted(random.sample(range(1, n), 4))
        a, b, c, dd = positions
        return tour[:a] + tour[c:dd] + tour[b:c] + tour[a:b] + tour[dd:]

    best_tour = None
    best_len = float('inf')

    # Initial NN tour from multiple starts
    for start in range(min(n, 3)):
        if time.time() - t0 >= budget * 0.3:
            break
        t1 = nearest_neighbor(start)
        tl = tour_length(t1)
        if tl < best_len:
            best_len = tl
            best_tour = t1[:]

    # Initial optimization
    time_for_init = t0 + budget * 0.4
    best_tour = two_opt(best_tour, time_for_init)
    if time.time() - t0 < time_for_init:
        best_tour = or_opt(best_tour, time_for_init)
    best_len = tour_length(best_tour)

