        restart_budget = min(remaining * 0.5, budget * 0.15)
        tl_limit = time.time() + restart_budget

        if n <= 100:
            # more random variety
            if random.random() < 0.3:
                s = random.randint(0, n-1)
                tour = nearest_neighbor(s)
            else:
                tour = double_bridge(best_tour)
        else:
            tour = double_bridge(best_tour)

        if time.time() - t0 >= budget * 0.95:
            break

        tl_limit = min(tl_limit, t0 + budget * 0.93)
        tour = two_opt(tour, tl_limit)
        if time.time() - t0 < tl_limit:
            tour = or_opt(tour, tl_limit)

        tl = tour_length(tour)
        if tl < best_len:
            best_len = tl
            best_tour = tour[:]

