                ci = tour[i]
                ni_ = (i+1)%n
                ci1 = tour[ni_]
                d_ci_ci1 = d(ci, ci1)
                for cj in neighbors[ci]:
                    j = pos[cj]
                    if j == i or j == ni_:
                        continue
                    nj = (j+1)%n
                    cj1 = tour[nj]
                    if d(ci, cj) >= d_ci_ci1:
                        break
                    gain = d_ci_ci1 + d(cj, cj1) - d(ci, cj) - d(ci1, cj1)
                    if gain > 0:
                        # reverse segment between ni_ and j
                        if ni_ <= j:
                            tour[ni_:j+1] = tour[ni_:j+1][::-1]
